'use client';

import React from 'react';
import { useActiveBranch } from '@/context/ActiveBranchContext';
import SalonServicesManager from '@/components/shared/salon/SalonServicesManager';
import { Store } from 'lucide-react';
import Link from 'next/link';

export default function OwnerServicesPage() {
    const { activeBranch, loading } = useActiveBranch();

    if (loading) return <div>Yükleniyor...</div>;

    if (!activeBranch) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-8">
                <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                    <Store className="w-8 h-8 text-text-muted" />
                </div>
                <h2 className="text-xl font-black text-text-main">Aktif Şube Seçilmedi</h2>
                <p className="text-text-secondary mt-2 mb-6">Hizmet yönetimi yapmak için lütfen yukarıdan bir şube seçin.</p>
                <Link href="/owner/salons" className="px-6 py-3 bg-primary text-white rounded-2xl font-bold">
                    Şubelerim'e Git
                </Link>
            </div>
        );
    }

    return (
        <div className="p-8">
            <div className="mb-8">
                <h1 className="text-2xl font-black text-text-main">Hizmet Yönetimi</h1>
                <p className="text-text-secondary font-medium mt-1">
                    <span className="text-primary font-bold">{activeBranch.name}</span> şubesinde sunulan hizmetleri düzenleyin.
                </p>
            </div>

            <SalonServicesManager salonId={activeBranch.id} />
        </div>
    );
}
